// Filter aktive Events und formatiere als sauberes JSON-Array
const items = $input.all();

function extractISO(datum) {
  if (!datum) return '';
  // "04.04.2026 · Wülfrath" → "2026-04-04"
  const m = datum.match(/(\d{2})\.(\d{2})\.(\d{4})/);
  if (m) return `${m[3]}-${m[2]}-${m[1]}`;
  // Multi-day "18.–23.07.2026" → "2026-07-23" (End-Datum für Archiv-Logik)
  const multi = datum.match(/[–-](\d{2})\.(\d{2})\.(\d{4})/);
  if (multi) return `${multi[3]}-${multi[2]}-${multi[1]}`;
  return '';
}

// Nur aktive Events (Status = 'aktiv')
const aktiv = items.filter(i => i.json.Status === 'aktiv');

// Sortierung nach Datum
aktiv.sort((a, b) => {
  const dA = extractISO(a.json.EventDatum);
  const dB = extractISO(b.json.EventDatum);
  return dA.localeCompare(dB);
});

const events = aktiv.map(i => ({
  name: i.json.EventName || '',
  link: i.json.EventLink || '',
  datum: i.json.EventDatum || '',
  isoDatum: extractISO(i.json.EventDatum),
  beschreibung: i.json['Event-Beschreibung'] || '',
  wochentag: i.json.Wochentag || '',
  anmeldestand: i.json.Anmeldestand || '',
  zusatz: i.json.Zusatzinfos || ''
}));

return [{ json: { events } }];
